 1	import * as React from 'react';
 2	import { FocusTrap, Menu, MenuList, MenuItem } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import useAutoComplete from './useAutoComplete';
 5	import { WithScrollContainer } from '../pipelines-tasks/tasks-details-pages/events/dom-utils';
 6	import { Popper } from '../popper';
 7	
 8	type AutoCompletePopoverProps = {
 9	  autoCompleteValues: string[];
10	  children: (contentRefCallback: (ref: HTMLElement) => void) => React.ReactNode;
11	  onAutoComplete: (newValue: string) => void;
12	};
13	
14	const AutoCompletePopover: React.FC<AutoCompletePopoverProps> = ({
15	  autoCompleteValues,
16	  children,
17	  onAutoComplete,
18	}) => {
19	  const { t } = useTranslation('plugin__pipelines-console-plugin');
20	
21	  const {
22	    contentRefCallback,
23	    focusTrapProps,
24	    insertAutoComplete,
25	    popperProps,
26	    menuWidth,
27	    options,
28	  } = useAutoComplete(autoCompleteValues, onAutoComplete);
29	
30	  return (
31	    <>
32	      {children(contentRefCallback)}
33	      <WithScrollContainer>
34	        {(scrollContainer) => (
35	          <Popper
36	            {...popperProps}
37	            placement="bottom-start"
38	            closeOnEsc
39	            closeOnOutsideClick
40	            container={scrollContainer}
41	            popperOptions={{
42	              modifiers: {
43	                hide: {
44	                  enabled: false,
45	                },
46	                preventOverflow: {
47	                  enabled: false,
48	                },
49	                flip: {
50	                  enabled: false,
51	                },
52	              },
53	            }}
54	          >
55	            <FocusTrap {...focusTrapProps}>
56	              <Menu
57	                style={{ maxHeight: 200, overflow: 'auto', width: menuWidth }}
58	                onSelect={(event, itemId: number) => {
59	                  const text = options[itemId];
60	                  if (text) {
61	                    insertAutoComplete(text);
62	                  }
63	                }}
64	              >
65	                <MenuList>
66	                  {options.length === 0 ? (
67	                    // There is a tab-index problem with the Menus from PF. If the first option is removed, it breaks tab indexes
68	                    // Need key 0 because of PF bug
69	                    <MenuItem key={0} itemId={-1} isDisabled>
70	                      {t('No options matching your criteria')}
71	                    </MenuItem>
72	                  ) : (
73	                    options.map((value, idx) => (
74	                      // Using index-based keys to get around PF bug, see above
75	                      // eslint-disable-next-line react/no-array-index-key
76	                      <MenuItem key={idx} itemId={idx}>
77	                        {value}
78	                      </MenuItem>
79	                    ))
80	                  )}
81	                </MenuList>
82	              </Menu>
83	            </FocusTrap>
84	          </Popper>
85	        )}
86	      </WithScrollContainer>
87	    </>
88	  );
89	};
90	
91	export default AutoCompletePopover;

